#include <bits/stdc++.h>
using namespace std;
int x,n;
long long a[20];
void s(int n) {
	while(n) {
		for(int i=x; i>=0; i--) {
			if(a[i]<=n) {
				n-=a[i];
				if(i>1) {
					cout<<"2(";
					s(i);
					cout<<")";
				}
				if(i==1) {
					cout<<"2";
				}
				if(n) {
					cout<<"+";
				}
				if(i==0) {
					cout<<"2(0)";
				}
			}
		}
	}
}
int main() {
	cin>>n;
	a[0]=1;
	for(int i=1; i<=20; i++) {
		a[i]=a[i-1]*2;
		x++;
	}
	s(n);
	return 0;
}
